import { NextResponse } from 'next/server';

interface PostRouteParams {
  id: string;
}

interface UpdatePostBody {
  title?: string;
  content?: string;
}

export async function GET(_request: Request, context: { params: Promise<PostRouteParams> }) {
  const { id } = await context.params;
  const post = {
    id: Number.parseInt(id, 10),
    title: `Post ${id}`,
    content: `This is the content for post ${id}`,
    createdAt: new Date().toISOString(),
  };

  return NextResponse.json(post);
}

export async function PUT(request: Request, context: { params: Promise<PostRouteParams> }) {
  const { id } = await context.params;
  const body = (await request.json()) as UpdatePostBody;
  const { title, content } = body;

  const updatedPost = {
    id: Number.parseInt(id, 10),
    title: title || `Post ${id}`,
    content: content || `Updated content for post ${id}`,
    updatedAt: new Date().toISOString(),
  };

  return NextResponse.json(updatedPost);
}

export async function DELETE(_request: Request, context: { params: Promise<PostRouteParams> }) {
  const { id } = await context.params;

  return NextResponse.json({ message: `Post ${id} deleted successfully` });
}
EOF

